final:
module verified_Gray_counter(
   input                clk ,
   input                rst_n,

   output reg [7:0]     Q  
);
    reg [7:0] gray_code;

    always@(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            Q <= 8'b0;
            gray_code <= 8'b0;
        end else begin
            gray_code <= gray_code + 1;
            Q <= (gray_code >> 1) ^ gray_code;
        end
    end
endmodule
